package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.repository.follow.FollowRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

class AlreadyFollowingException(message: String) : RuntimeException(message)
class NotFollowingException(message: String) : RuntimeException(message)
class SelfFollowException(message: String) : RuntimeException(message)

@Service
class UserService(
    private val followRepository: FollowRepository,
) {
    companion object {
        const val STATUS_ACTIVE = 0
        const val STATUS_CANCELLED = 1
    }

    @Transactional
    fun follow(followerId: String, followeeId: String): FollowEntity {
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 팔로우할 수 없습니다.")
        }

        val existing = followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)

        if (existing.isPresent) {
            val follow = existing.get()
            if (follow.status == STATUS_ACTIVE) {
                throw AlreadyFollowingException("이미 팔로우 중입니다: followerId=$followerId, followeeId=$followeeId")
            }
            // 이전에 취소된 팔로우 관계 재활성화
            follow.status = STATUS_ACTIVE
            return followRepository.save(follow)
        }

        val follow = FollowEntity(
            followerId = followerId,
            followeeId = followeeId,
            status = STATUS_ACTIVE,
        )
        return followRepository.save(follow)
    }

    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        if (followerId == followeeId) {
            throw SelfFollowException("자기 자신을 언팔로우할 수 없습니다.")
        }

        val follow = followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)
            .filter { it.status == STATUS_ACTIVE }
            .orElseThrow { NotFollowingException("팔로우 관계가 없습니다: followerId=$followerId, followeeId=$followeeId") }

        follow.status = STATUS_CANCELLED
        followRepository.save(follow)
    }

    @Transactional(readOnly = true)
    fun getFollowings(followerId: String): List<FollowEntity> {
        return followRepository.findByFollowerIdAndStatus(followerId, STATUS_ACTIVE)
    }

    @Transactional(readOnly = true)
    fun getFollowers(followeeId: String): List<FollowEntity> {
        return followRepository.findByFolloweeIdAndStatus(followeeId, STATUS_ACTIVE)
    }

    @Transactional(readOnly = true)
    fun getFollowingCount(followerId: String): Long {
        return followRepository.countByFollowerIdAndStatus(followerId, STATUS_ACTIVE)
    }

    @Transactional(readOnly = true)
    fun getFollowerCount(followeeId: String): Long {
        return followRepository.countByFolloweeIdAndStatus(followeeId, STATUS_ACTIVE)
    }

    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)
            .filter { it.status == STATUS_ACTIVE }
            .isPresent
    }
}
