    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // =============================================
    // follow()
    // =============================================

    @Test
    fun `should follow successfully when no existing relationship`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val savedEntity = FollowEntity(
            id = "follow-1",
            followerId = followerId,
            followeeId = followeeId,
            status = UserService.STATUS_ACTIVE,
        )
        whenever(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.empty())
        whenever(followRepository.save(any())).thenReturn(savedEntity)

        // when
        val result = userService.follow(followerId, followeeId)

        // then
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followeeId).isEqualTo(followeeId)
        assertThat(result.status).isEqualTo(UserService.STATUS_ACTIVE)

        val captor = argumentCaptor<FollowEntity>()
        verify(followRepository).save(captor.capture())
        assertThat(captor.firstValue.followerId).isEqualTo(followerId)
        assertThat(captor.firstValue.followeeId).isEqualTo(followeeId)
        assertThat(captor.firstValue.status).isEqualTo(UserService.STATUS_ACTIVE)
    }

    @Test
    fun `should reactivate follow when previous relationship was cancelled`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val cancelledFollow = FollowEntity(
            id = "follow-1",
            followerId = followerId,
            followeeId = followeeId,
            status = UserService.STATUS_CANCELLED,
        )
        whenever(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.of(cancelledFollow))
        whenever(followRepository.save(any())).thenReturn(cancelledFollow)

        // when
        val result = userService.follow(followerId, followeeId)

        // then
        assertThat(result.status).isEqualTo(UserService.STATUS_ACTIVE)
        verify(followRepository).save(cancelledFollow)
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val activeFollow = FollowEntity(
            id = "follow-1",
            followerId = followerId,
            followeeId = followeeId,
            status = UserService.STATUS_ACTIVE,
        )
        whenever(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.of(activeFollow))

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followeeId)
        }
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw SelfFollowException when following self`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }
        verify(followRepository, never()).findByFollowerIdAndFolloweeId(any(), any())
        verify(followRepository, never()).save(any())
    }

    // =============================================
    // unfollow()
    // =============================================

    @Test
    fun `should unfollow successfully when following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val activeFollow = FollowEntity(
            id = "follow-1",
            followerId = followerId,
            followeeId = followeeId,
            status = UserService.STATUS_ACTIVE,
        )
        whenever(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.of(activeFollow))
        whenever(followRepository.save(any())).thenReturn(activeFollow)

        // when
        userService.unfollow(followerId, followeeId)

        // then
        assertThat(activeFollow.status).isEqualTo(UserService.STATUS_CANCELLED)
        verify(followRepository).save(activeFollow)
    }

    @Test
    fun `should throw NotFollowingException when not following`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        whenever(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.empty())

        // when & then
        assertThrows<NotFollowingException> {
            userService.unfollow(followerId, followeeId)
        }
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw NotFollowingException when follow relationship is already cancelled`() {
        // given
        val followerId = "user-A"
        val followeeId = "user-B"
        val cancelledFollow = FollowEntity(
            id = "follow-1",
            followerId = followerId,
            followeeId = followeeId,
            status = UserService.STATUS_CANCELLED,
        )
        whenever(followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId))
            .thenReturn(Optional.of(cancelledFollow))

        // when & then
        assertThrows<NotFollowingException> {
            userService.unfollow(followerId, followeeId)
        }
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw SelfFollowException when unfollowing self`() {
        // given
        val userId = "user-A"

        // when & then
        assertThrows<SelfFollowException> {
            userService.unfollow(userId, userId)
        }
        verify(followRepository, never()).findByFollowerIdAndFolloweeId(any(), any())
    }

    // =============================================
    // getFollowings()
    // =============================================

    @Test
    fun `should return followings when user has active follows`() {
        // given
        val followerId = "user-A"
        val followings = listOf(
            FollowEntity(id = "f1", followerId = followerId, followeeId = "user-B", status = UserService.STATUS_ACTIVE),
            FollowEntity(id = "f2", followerId = followerId, followeeId = "user-C", status = UserService.STATUS_ACTIVE),
        )
        whenever(followRepository.findByFollowerIdAndStatus(followerId, UserService.STATUS_ACTIVE))
            .thenReturn(followings)

        // when
        val result = userService.getFollowings(followerId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followeeId }).containsExactlyInAnyOrder("user-B", "user-C")
        verify(followRepository).findByFollowerIdAndStatus(followerId, UserService.STATUS_ACTIVE)
