    @Test
    fun `should return empty list when user has no followings`() {
        // given
        val followerId = "user-A"
        whenever(followRepository.findByFollowerIdAndStatus(followerId, UserService.STATUS_ACTIVE))
            .thenReturn(emptyList())

        // when
        val result = userService.getFollowings(followerId)

        // then
        assertThat(result).isEmpty()
    }

    // =============================================
    // getFollowers()
    // =============================================

    @Test
    fun `should return followers when user has active followers`() {
        // given
        val followeeId = "user-B"
        val followers = listOf(
            FollowEntity(id = "f1", followerId = "user-A", followeeId = followeeId, status = UserService.STATUS_ACTIVE),
            FollowEntity(id = "f2", followerId = "user-C", followeeId = followeeId, status = UserService.STATUS_ACTIVE),
